"import os\n\nsearch_root = r\"C:\\Users\\John Jacob\\Desktop\\extras\\test-box\\vemi\"\nfound = []\n\nfor root, dirs, files in os.walk(search_root):\n    # Skip python caches and temporary folders if appropriate, but search as much as possible\n    if \"__pycache__\" in root or \".git\" in root:\n        continue\n    for file in files:\n        if file.endswith((\".c\", \".h\", \".txt\", \".bak\", \".tmp\")):\n            path = os.path.join(root, file)\n            try:\n                with open(path, 'r', encoding='utf-8', errors='ignore') as f:\n                    content = f.read()\n                    if \"BemiBiosEntryPoint\" in content and \"PostDetectTopology\" in content:\n                        found.append((path, len(content)))\n            except Exception:\n                pass\n\nprint(f\"Found {len(found)} files matching search criteria:\")\nfor path, length in found:\n    print(f\"  {path} (length={length})\")\n"